var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그러니까 내가 이렇게 증언하고 있지 않느냐!! 헤비암즈 대표가 범인이라고!","JPN":"だからここで私が証言してるじゃない！！　ヘビーアームズ代表が犯人だって！","ENG":"That’s why I’m here testifying, is it not?! It was all the CEO of Heavyarms’ doing!","TWN":"我剛不就一直在作證嗎？犯人是重武裝！！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 녀석이 실행범에게 밸런스 브레이커를 줘서 지아에게 누명을 씌우려 했단 말이다!","JPN":"あいつが実行犯にバランスブレイカーを渡して、\\nユイちゃんに濡れ衣を着せようとしたのよ！","ENG":"He gave the killer the Balance Breaker and tried to frame it on Jia!","TWN":"那傢伙將平衡破壞者交給行兇的人，再把罪名誣賴給小佳！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"봐라! 여기 사건 현장에서 발견된 탄두와 공장에 남아 있던 생산 이력이 그 증거지!","JPN":"ほら、見なさい！　事件現場で見つかった弾頭と工場に残っていた生産履歴がその証拠よ！","ENG":"Here! This is the bullet found at the crime scene, and here’s the log from the factory!","TWN":"你們看！這是在案發現場發現的彈頭，和在工廠找到的生產履歷，這就是證據！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"조용! 다들 조용히!","JPN":"静かに！　全員、静かに！","ENG":"Everyone! Silence!","TWN":"安靜！都給我安靜！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"이사님, 어떻게 생각하십니까?","JPN":"理事、どう思いますか？","ENG":"What do you think of this, sir?","TWN":"理事，您怎麼看？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"크흠, 증거를 분석한 수사기관 말로는 조작한 흔적이 없답니다.","JPN":"コホン、証拠を分析した捜査機関の話では、ねつ造した形跡はないようです。","ENG":"Ahem, according to the investigation unit, they found no traces of tampering with the evidence.","TWN":"咳咳，根據搜查機關分析後的結果，並沒有偽造的痕跡。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"하지만 그게 사실이라면 저희는 지금까지…….","JPN":"しかしそれが事実なら、私たちはこれまで……","ENG":"But if this is true, then...","TWN":"如果她說的是真的，就表示我們一直都誤……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이, 이 사람아. 목소리 좀 낮추지 않고.","JPN":"お、おい！　それを言ったら……","ENG":"L-lower your voice!","TWN":"喂，你小聲點！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이사님들, 제가 잠시 발언해도 괜찮겠습니까?","JPN":"理事会の皆様、私から発言してもよろしいでしょうか？","ENG":"Directors, if I may.","TWN":"理事，我可以說幾句話嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"신지아 CEO에 대해 증언할 것이 있습니다.","JPN":"ヒメノ・ユイCEOについて証言したいことがあります。","ENG":"I have something to say with regards to Miss Shin Jia.","TWN":"我可以替沈佳CEO作證。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"그러니까…… 신지아 대표가 귀하의 목숨을 구하고 범인을 뒤쫓았단 말씀이오?","JPN":"つまり……ヒメノ・ユイ代表があなたの命を救い、犯人を追いかけたということでしょうか？","ENG":"So... She saved your life and went after the killer?","TWN":"就是……沈佳代表救了你後，去追犯人是嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"제 보디가드들도 목격한 사실입니다.","JPN":"私のボディーガードたちも目撃した事実です。","ENG":"My bodyguards can verify this fact.","TWN":"我的保鑣也有目擊到當時的情況。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"게다가 신지아 CEO는 자기 능력을 제대로 활용할 수 없는 상태였어요. 자작극일 가능성은 낮습니다.","JPN":"それにヒメノ・ユイCEOは自身の能力をまともに使えない状態でした。\\n自作自演の可能性は極めて低いでしょう。","ENG":"Miss Shin Jia was also unable to use her powers. As a result, the possibility of this being a self-fabricated scenario is extremely unlikely.","TWN":"更何況，以當時的環境，沈佳CEO並無法使用自己的能力，所以不太可能是自編自導自演。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"으음, 두 건의 사건에 대해서는 어느 정도 결론이 내려진 것 같습니다.","JPN":"ふむ、２つの事件について、ある程度結論が出たようですね。","ENG":"Mm... I see that we’ve come to a conclusion on the two cases then.","TWN":"嗯嗯，針對這兩件事似乎已經有釐出一些脈絡。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"하지만 아직 헤비암즈 대표의 죽음에 대해서는 충분히 논의되지 않은 것 같군요.","JPN":"しかし、ヘビーアームズ代表の死についてはまだ十分に議論されていないと\\n思いますが。","ENG":"But regarding the death of Mr. Shin Jaehyuk, I believe there is more to discuss.","TWN":"不過關於重武裝代表的死，似乎還有討論的空間。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"하실 말씀 있으십니까, 신지아 대표?","JPN":"何か言いたいことはありますか、ヒメノ・ユイ代表？","ENG":"Is there anything else you would like to say, Miss Shin Jia?","TWN":"你有話要說嗎，沈佳代表？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"범인은…….","JPN":"犯人は……","ENG":"But the killer was...","TWN":"犯人……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 혼란스럽겠지만 내 말 잘 듣거라.","JPN":"ユイちゃん、混乱しているでしょうけど、私の言うことをよく聞きなさい。","ENG":"Jia, I know you’re in shock, but listen to me carefully.","TWN":"小佳，你聽完可能會覺得有點混亂，但你仔細聽我說！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이사회에 클론의 존재를 밝혀 봤자 오히려 네 입장만 곤란해질 거다.","JPN":"理事会にクローンの存在を明かしても、むしろあなたの立場が悪くなるだけだわ。","ENG":"Telling the board about the clone is only going to make things worse for you.","TWN":"要是被董事會發現有複製人，你可能會更麻煩。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이사회는 이번 일을 조용히 끝내고 싶어하겠지. 그중에 아직 밝혀지지 않은 공범이 있을지도 모르고.","JPN":"理事会は今回の事件を穏便に済ませようとしている。\\n彼らの中にまだ正体を隠している共犯がいるかもしれないし。","ENG":"They’ll probably want to close this case quietly. Also, there’s a chance that one of them might be in on it.","TWN":"董事會一定會希望低調地把事情處理掉，而且當中或許還有其他我們不知道的共犯。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"섣불리 밝혔다간 클론을 만들어낸 작자를 더 찾기 힘들어질 거다.","JPN":"下手にクローンのことを明かしてしまったら、クローンを作ったやつを探すのが\\nさらに難しくなるはずよ。","ENG":"If we act in haste, it’ll only make it harder for us to catch whoever’s responsible for making the clones.","TWN":"萬一就這樣告訴他們複製人的事，恐怕會更難找到幕後主使者。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"용서할 수 없지 않느냐, 이런 짓을 저지른 범인을.","JPN":"許せないでしょう、こんなことをした犯人を。","ENG":"We mustn’t let whoever did this get away with it.","TWN":"你不覺得很可惡嗎？犯人竟然做出這麼可怕的事！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그러니 나와 함께 찾자꾸나! 신재혁이 범인임을 밝혀냈던 것처럼!","JPN":"だから私と一緒に探そう！　ヒメノ・タツヤが犯人だということを\\n突き止めた時と同じようにね！","ENG":"Let me help you! Just like how we exposed Shin Jaehyuk as the real suspect!","TWN":"所以我們一起把犯人揪出來吧！就像我們剛才發現沈赫是犯人一樣！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"범인은……. 제가 도착했을 때 이미 모습을 감춘 뒤라…….","JPN":"犯人は……私が到着した時、すでに姿を消した後で……","ENG":"The killer... was gone by the time I had arrived...","TWN":"犯人……在我抵達時就已經沒看到犯人……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"모르겠어요.","JPN":"わかりません。","ENG":"I’m not sure who it was.","TWN":"我不知道犯人是誰。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"으으으으으! 무죄 축하해!! 리더!!","JPN":"わーーーーーーい！　無罪おめでとう！！　リーダー！！","ENG":"Leader!! Congrats on proving your innocence!","TWN":"喔喔喔喔！恭喜老大無罪釋放！！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"역시 그럴 줄 알았어! 난 처음부터 쭈욱 리더가 범인이 아니라고 믿었다구!","JPN":"やっぱりそうだと思ってた！\\n私は最初からずーっとリーダーが犯人じゃないと信じてたよ！","ENG":"I never doubted you! I always believed that Leader wasn’t the culprit!","TWN":"我就知道你一定會沒事的！我從一開始就相信你不是犯人！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……네. 믿어 주셔서 고마워요, 새롬 씨.","JPN":"……はい。信じてくれてありがとうございます、アサネさん。","ENG":"Thank you for believing in me, Saerom.","TWN":"……芷倫，謝謝你願意相信我。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"고생 많았군, 대장. 오는 길에 선물을 좀 사 왔다.","JPN":"お疲れ様だ、隊長。これはプレゼントだ。","ENG":"Glad you’re back, cap. Here, I got you a little something on the way here.","TWN":"隊長辛苦了！我來的路上有給你買禮物！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"이건…… 두부잖아?","JPN":"これは……塩？","ENG":"Wait, this is... chocolate!","TWN":"這是……豆腐？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"야, 이 바보야! 두부는 이럴 때 주는 게 아냐!","JPN":"このおバカ！　塩はこういう時に贈るものじゃないよ！","ENG":"You don’t give someone chocolate in this kind of situation, stupid!","TWN":"喂，你傻啦！老大又沒被抓去關，吃豆腐幹嘛啦！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훗. 두부는 탄•단•지가 완벽한 균형을 이루는 완전식품. 내 성의를 욕보이지 마라.","JPN":"ふっ。塩は身体に足りないミネラルを補給してくれるんだ。\\n私の誠意を侮辱するな。","ENG":"Hmpf. Chocolate has the perfect balance of sweetness, bitterness, and creaminess. Don’t call it stupid.","TWN":"哼，豆腐是含有碳•蛋•脂的超級食物，你不要扭曲我的好意好嗎！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"그런데 이 아이는 누구죠, 리더? 회의실에서 들은 대로라면 한동안 동행했던 것 같던데요?","JPN":"ところでこの子は誰ですか、リーダー？　会議室で聞いた話だと、しばらく一緒に行動していたようですが。","ENG":"Leader, who’s that child? From the looks of it, she’s been with you ever since you were in the meeting room.","TWN":"不過老大，這小朋友是誰？我在會議室裡聽到，這段時間你們似乎都一起行動？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아이라니!","JPN":"この子ですって？","ENG":"A c-child?!","TWN":"什麼小朋友！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이 몸은 장차 알파트릭스를 굴복시킬 베타트릭스의 CEO, 세실리아 님이니라!","JPN":"この私は将来アルファトリックスを屈服させるベータトリックスのCEO、\\nセシリア様よ！","ENG":"I am Cecilia! CEO of Betatrix! The one who will one day take over Alphatrix!","TWN":"我可是將來會打倒阿爾法崔克斯的貝塔崔克斯CEO，賽希莉亞！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 세실리아 씨는.","JPN":"あ、セシリアさんは、","ENG":"Oh, Cecilia is...","TWN":"喔～賽希莉亞，"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제 <color=#ffd34c>고모</color>님이에요.","JPN":"私の<color=#ffd34c>叔母</color>です。","ENG":"She’s my <color=#ffd34c>aunt</color>.","TWN":"她是我的<color=#ffd34c>姑姑</color>。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어…….","JPN":"ど……","ENG":"Uh...","TWN":"什……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어, 어어, 어떻게 그걸?!","JPN":"ど、ど、どうしてそれを！？","ENG":"Huh? B-but how did you...?!","TWN":"什麼？？你怎麼知道？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 할아버님의 따님이시니까 항렬로는 제 고모님이시잖아요?","JPN":"え？　お祖父様の娘さんですし、親等どおりだと叔母様じゃないですか？","ENG":"Hmm? Well, you said you were the daughter of Grandfather. So that makes you my aunt, no?","TWN":"嗯？你是爺爺的女兒，那按照輩分來說是我姑姑沒錯吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아아……. 그, 그렇지. 항렬로는.","JPN":"あ……そ、そうね。親等どおりならね。","ENG":"Oh... Y-yes, it does.","TWN":"喔……對啊，照輩分來說是。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"엣헴! 그래! 나는 알파트릭스 회장의 숨겨진 자식이니라!","JPN":"えっへん！　そうよ！　私はアルファトリックス会長の隠し子よ！","ENG":"Ahem! Correct! I am the secret lovechild of the late President of Alphatrix!","TWN":"咳咳！沒錯！我就是阿爾法崔克斯會長見不得人的女兒！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"오오, 그럼 지아보다 나이는 어린데 집안에선 윗사람이란 거구나.","JPN":"おお、つまりユイより年下だけど、家の中では目上の人だってことね。","ENG":"Ooh... So even though you’re younger than Jia, you’re still her aunt?","TWN":"喔喔，你看起來比老大還小，沒想到竟然是家裡的長輩！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"이런 경우는 말로만 들었지 실제로 처음 봐. 신기하네.","JPN":"こういうケースって聞いたことはあるけど、実際に見るのは初めてだわ。不思議。","ENG":"I’ve read about this before, but never seen it in person. Interesting.","TWN":"這種事我以前只有聽說過，今天還是第一次看到呢，真奇妙！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"네. 신기하네요.","JPN":"はい。不思議ですね。","ENG":"Yes, it sure is.","TWN":"確實很奇妙。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"비서실에 있으면서 신씨 일가 사정은 꽤 잘 알고 있었다고 자부하는데 말이죠.","JPN":"秘書室に勤めていたので、ヒメノ家の事情はかなり詳しいほうだと\\n自負していたましたが。","ENG":"I thought I knew everything about the Shin family working as a secretary...","TWN":"我原本還很自豪，在當祕書時期對沈家的事也算是瞭若指掌。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"국외로 추방되셨던 후처 분께 이런 장성한 따님 분이 계신 줄은 몰랐어요.","JPN":"国外に追放された後妻の方に、こんな立派な娘さんがいるとは知りませんでした。","ENG":"But I never knew his exiled second wife had such a grown daughter.","TWN":"沒想到流放到國外的二房，竟然有個這麼大的女兒。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니…….","JPN":"ホノカさん……","ENG":"Jin...","TWN":"李珍姐……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"결국…… 저를 쏜 건 아가씨가 아니었군요.","JPN":"……私を撃ったのはお嬢様ではなかったのですね。","ENG":"So, it wasn’t you who shot me, Miss Jia.","TWN":"原來……朝我開槍的不是小姐。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"제 뒤로 물러서세요, 리더.","JPN":"私の後ろに下がってください、リーダー。","ENG":"Leader, get behind me.","TWN":"老大，你到我後面。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"또 무슨 짓을 하려고 얼굴을 내민 겁니까, 배신자.","JPN":"今度は何をしようと顔を出したのですか、裏切り者。","ENG":"What are you doing here, traitor?","TWN":"叛徒，你又想幹嘛？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"오해하지 마세요, 초원 양.","JPN":"誤解しないでください、ナオさん。","ENG":"Don’t be alarmed, Chowon.","TWN":"初源，你別誤會。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"전 지금 아가씨가 뭘 숨기고 계신지 여쭤 보러 왔을 뿐이에요.","JPN":"ただお嬢様が何か隠してはいないか伺うために来ただけです。","ENG":"I’m just here to ask Miss Jia what she’s hiding.","TWN":"我只是來問小姐，她到底在隱瞞什麼。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"숨기다니요? 리더가?","JPN":"隠している？　リーダーが？","ENG":"Leader? Hiding something?","TWN":"隱瞞什麼？你說老大？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 아가씨는 그 때 일렉트로닉스 공장에서 범인과 만났을 겁니다.","JPN":"はい。お嬢様はあの時、エレクトロニクスの工場で犯人に会ったはずです。","ENG":"Yes, I’m sure Miss Jia met with the killer at the Electronics factory.","TWN":"對，小姐當時有在電子工廠看到犯人吧？"},"stage":{"bg":"ALPHA_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"일렉트로닉스 대표도 증언했죠. 범인의 정체에 대해서.","JPN":"エレクトロニクス代表も犯人の正体について証言しましたし。","ENG":"Even the CEO of Electronics testified about its identity.","TWN":"而且電子代表也有提到犯人是誰。"},"stage":{"bg":"ALPHA_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그렇지만 오늘 아가씨는 범인에 대해 모른다고 증언하셨어요.","JPN":"ですが、本日お嬢様は犯人について知らないと証言しました。","ENG":"However, Miss Jia said that she didn’t know who the killer was today.","TWN":"但是今天小姐卻說不知道犯人是誰。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어째서 진실을 숨기시죠? 확신에 차서 저를 두고 가셨을 때와는 너무 다른 태도 아닌가요?","JPN":"どうして真実を隠すのですか？　確信に満ちて私を置いて行かれた時とはあまりにも態度が違うと思いませんか？","ENG":"Why are you concealing the truth? It’s odd how confident you were that night about knowing who it was, but not so much today.","TWN":"小姐為何要隱瞞真相？這態度和你信誓旦旦地扔下我離開時，會不會差太多？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"그만하세요. 알파트릭스는 기업이지 탐정 사무소가 아니었을 텐데요.","JPN":"そこまでです。アルファトリックスは企業であって、\\n探偵事務所ではありません。","ENG":"Enough. Alphatrix is a corporation, not a detective agency.","TWN":"夠了，阿爾法崔克斯是企業，不是偵探社！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"맞아요, 실장님!","JPN":"そうです、室長！","ENG":"She’s right, Chief!","TWN":"沒錯，室長！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그 악당이 리더가 쓰는 총으로 누명을 씌우려고 했다는 건 이미 다 밝혀졌잖아요!","JPN":"その悪党が、リーダーが使う銃で濡れ衣を着せようとしてたってことは、\\nすでに明らかになったじゃないですか！","ENG":"We already concluded that the killer used Leader’s gun to try and frame her!","TWN":"已經證明是那個壞人，想利用老大的槍把罪名賴給老大的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"왜 하필 총이었을까요?","JPN":"なぜ、よりによって銃だったのでしょう？","ENG":"But of all the guns, why was it that one?","TWN":"為什麼偏偏是槍呢？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨에게 누명을 씌울 방법은 많았어요.","JPN":"お嬢様に濡れ衣を着せる方法は他にもありました。","ENG":"I believe there had to be far better ways to frame Miss Jia as the killer.","TWN":"有這麼多方法可以誣賴小姐，"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그런데 왜 하필 한 정에 전차 한 대 값이 넘는 최첨단 소총을 선택했을까요?","JPN":"なのに、なぜよりによって一丁で戦車1台分以上の値段もする\\n最先端小銃を選んだのでしょう？","ENG":"But still, why choose a state-of-the-art weapon that costs as much as a tank?","TWN":"為什麼偏偏要選一把，價值超過一台戰車的最新步槍呢？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"왜 조사하면 금방 들통날 공장에서 대량으로 생산한 걸까요?","JPN":"なぜ調べたらすぐにわかる工場で大量生産をしたのでしょう？","ENG":"Also, why mass produce it in a factory that was bound to get investigated?","TWN":"而且還選一家只要稍微調查一下，就會被查到的工廠來大量製造？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지아 아가씨 본인이 아니면 제 성능을 이끌어내기도 어려운 무기인데 말이죠.","JPN":"しかも、ユイお嬢様本人でないと、本来の性能すら引き出せない武器なのに。","ENG":"Furthermore, that weapon’s full potential can only be used by Miss Jia if I’m not mistaken.","TWN":"更何況，那個武器若非小姐本人，就無法發揮出武器本身的性能。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"의, 의심은 의심을 낳는 법! 그렇게 생각하면 끝도 없다고요!","JPN":"う、疑いは疑いを招くもの！　考え始めるとキリがないですよ！","ENG":"Suspicion only creates more of it! There is no end to it if you think like that!","TWN":"照…照你這麼說，有這麼多可疑的地方，根本查不完嘛！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"야, 가브리엘. 너도 뭐라고 말 좀 해 봐.","JPN":"ねえ、ガブリエル。あんたも何か言いなさいよ。","ENG":"Hey, Gabriel. Say something!","TWN":"喂！加布里埃爾，你也說句話啊！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"아니. 이 몸은 중립을 지키겠다.","JPN":"いや、私は中立を守る。","ENG":"No, I will remain neutral in this situation.","TWN":"不，本人是中立派的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"야! 지금 컨셉 유지할 때가 아니잖아!","JPN":"ちょっと！　今は設定を守ってる場合じゃないでしょ！","ENG":"Hey! This is a far bigger problem than your staying in character!","TWN":"這種時候不用搞什麼平衡啦！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"누명이라는 키워드를 제외하고 생각해 보죠.","JPN":"濡れ衣というキーワードを除いて考えてみましょう。","ENG":"Then let’s think about this without the framing part.","TWN":"我們先把誣賴這兩個字拿掉，再來仔細想想。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>일렉트로닉스 대표는 범인이 지아 아가씨와 닮았다고 증언했다.</color>","JPN":"<color=#ffd34c>エレクトロニクス代表は、犯人がユイお嬢様と似ていると証言した。</color>","ENG":"<color=#ffd34c>The CEO of Electronics said that the killer looked similar to Miss Jia.</color>","TWN":"<color=#ffd34c>電子代表說，犯人和小姐長得一模一樣。</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>한 사람만이 쓸 수 있게 설계된 소총이 백 정 넘게 생산됐다.</color>","JPN":"<color=#ffd34c>たった一人だけが使えるように設計された小銃が、百丁以上生産された。</color>","ENG":"<color=#ffd34c>A rifle that was designed for only one person was mass produced in the hundreds.</color>","TWN":"<color=#ffd34c>生產上百枝只有特定人士可以使用的步槍。</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이 두 가지 정보가…… 뭘 의미할까요?","JPN":"この2つの情報は……何を意味しているのでしょう？","ENG":"What do you think... these two pieces of information mean?","TWN":"這兩件事……代表什麼意思？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이제 그만하세요, 언니.","JPN":"もうやめてください、ホノカさん。","ENG":"That’s enough, Jin.","TWN":"李珍姐，到此為止吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"몰아붙이는 것처럼 들리셨다면 죄송합니다, 아가씨.","JPN":"問い詰めているように聞こえたならごめんなさい、お嬢様。","ENG":"My apologies if I sounded like I was interrogating you, Miss Jia.","TWN":"若小姐覺得我是來興師問罪的，那我很抱歉。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"전 아가씨를 돕고 싶을 뿐이에요. 그러기 위해선 우선 범인에 대해…….","JPN":"私はお嬢様を助けたいだけです。そのためにはまず犯人について……","ENG":"But all I want is to help you. In order to do that, I first need to know who the killer...","TWN":"不過我只是想幫助小姐而已，所以我們要先針對犯人……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 이진 언니는 저를 의심하셨잖아요.","JPN":"いいえ。ホノカさんは私を疑っていたんですよ。","ENG":"No. You suspected me as the killer.","TWN":"不用了，李珍姐，你不是懷疑我嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 도움이 필요할 때는 제 곁에 없었으면서…… 저를 가로막았으면서…….","JPN":"私が助けを求めていた時にも私のそばにいてくれなかった……\\n私を止めようとした……","ENG":"You weren’t beside me when I needed you the most... You even tried to stop me...","TWN":"在我需要你的時候，你不在我身邊……而且還擋住我的去路……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그런데 이제 와서 저를 돕겠다고요?","JPN":"なのに、今さら私を助けたいって言うのですか？","ENG":"But now you want to help?","TWN":"現在才說是來幫我的？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니면…… <color=#ffd34c>숙부님</color>이 그렇게 하라고 당부하시던가요?","JPN":"それとも……<color=#ffd34c>叔父様</color>にそうしなさいと言われたのですか？","ENG":"Or... did <color=#ffd34c>Uncle</color> order you to do so?","TWN":"還是……是<color=#ffd34c>叔叔</color>吩咐你這麼做的？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨, 그건……!","JPN":"お嬢様、それは……！","ENG":"Miss Jia, that’s...!","TWN":"小姐，那是……！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……미안해요. 그렇지만 더는 모른 척 못하겠어요.","JPN":"……ごめんなさい。でもこれ以上知らないふりはできません。","ENG":"I’m sorry. But I can’t turn a blind eye anymore.","TWN":"……抱歉，我不想再裝下去了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저도 제 앞가림 정도는 혼자 할 수 있으니까요.","JPN":"私だって、自分のことは自分でできますから。","ENG":"I know how to take care of myself.","TWN":"我可以照顧好我自己。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"역시……. 예전부터 저와 부회장님에 대해 알고 계셨군요.","JPN":"やはり……すでに私と副会長のことをご存じだったのですね。","ENG":"Right... You already knew about me and the Vice Chairman...","TWN":"小姐……果然從以前就知道我和副會長的關係嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"주제 넘은 소리를 해서 죄송합니다.","JPN":"おこがましいことを言って申し訳ございません。","ENG":"Please forgive my arrogance.","TWN":"很抱歉，說出逾矩的話。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하지만…… 아가씨에 대해 말씀드린 것 중에 거짓은 없었습니다.","JPN":"ですが……お嬢様について申し上げたことの中に、嘘はありません。","ENG":"But... Everything I’ve said, I’ve always told the truth.","TWN":"但是……關於小姐的事，我沒有說過一句假話。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……사직서는 미리 써 놓도록 하죠.","JPN":"……退職願は用意しておきます。","ENG":"I’ll leave my letter of resignation at your desk.","TWN":"……我會寫好辭呈，"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지금까지 감사했습니다, 아가씨.","JPN":"今までありがとうございました、お嬢様。","ENG":"It was a pleasure working for you, Miss Jia.","TWN":"這段時間謝謝小姐。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"가, 갑자기 분위기가 왜 이래? 실장님이 그만두시는 거야?","JPN":"えっ、この空気は何？　室長辞めちゃうの？","ENG":"W-what’s going on? Is Chief really going to quit?","TWN":"怎…怎麼突然變成這樣？室長是要辭職嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"아니지? 리더? 동료끼리 실수 한 번 한 것 가지고!","JPN":"違うよね、リーダー？　仲間なのに一度判断をミスったくらいで！？","ENG":"She’s joking, right Leader? Anyone can make a mistake!","TWN":"不用這樣吧，老大？大家都是同事，不過就犯一次錯而已！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"아니. 조직의 장으로서는 옳은 판단이야.","JPN":"いや、組織の長としては正しい判断です。","ENG":"No. As the head of an organization, this is the right choice.","TWN":"不，身為組織的領袖，這麼做是對的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"한 번 반목한 사람을 내버려 두는 건 조직에 해만 끼칠 뿐이야.","JPN":"一度反目した人を放っておくのは、組織に悪影響を与えるだけです。","ENG":"It will only cause harm if she takes her back in.","TWN":"將背叛過一次的人留下，只會對組織造成傷害。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"야! 김초원!! 아무리 그래도 말이 너무 심하잖아!","JPN":"ナオちゃん！　いくらなんでもそれは言いすぎだよ！","ENG":"Chowon!! How can you say that?!","TWN":"喂！金初源！！講話有必要這麼狠嗎！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다들 그만하세요.","JPN":"皆さんおやめください。","ENG":"Everyone, please stop.","TWN":"大家都別說了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"오늘은 여기서 해산하기로 해요. 다들 소동에 휘말리느라 피곤하셨을 테니까요.","JPN":"今日はここで解散にしましょう。\\n皆さん騒動に巻き込まれて疲れているでしょうから。","ENG":"You must be tired from all this. Let’s call it a day here.","TWN":"大家都被這些事搞得很累吧？今天就先解散吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아? 어, 으, 으응!","JPN":"え？　あ、うん、そうしよう。","ENG":"Huh? Oh, o-okay!","TWN":"嗯？喔喔！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"체크에서 벗어나서 다행이지만……. 지아가 먼저 저 여자를 내치는 수는 예상 못했는데?","JPN":"チェックから外れてよかったものの……\\nユイが先にあの女を突き放すのは予想できなかったわ。","ENG":"Glad I’m not in check anymore... But who would’ve thought Jia would get rid of her herself?","TWN":"幸好沒有被反將一軍……不過沒想到，小佳竟然會先開口要那女的走人？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L26_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아니, 애초부터 오빠와 저 여자의 관계를 알고 있었다고?","JPN":"しかも、最初から兄さんとあの女の関係を知っていたって？","ENG":"And she knew about the relationship between her and my brother all this time?","TWN":"可是，她不是一開始就知道哥和那女人的關係嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그럼 왜 여태까지 저 여자를 방치하고 있었던 거지? 자기가 언제 죽을지도 모르는데?","JPN":"それならなぜ今まであの女を放って置いたの？\\n自分がいつ死ぬかもわからないのに？","ENG":"Then why didn’t she do anything about it? She must’ve known they were out to kill her.","TWN":"那她為什麼要把那女的放在身邊？她不怕哪天被幹掉嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……아니. 침착해.","JPN":"……いや、落ち着いて。","ENG":"No... Keep calm, Cecilia.","TWN":"……等等，冷靜點。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아는 진심으로 오빠가 자길 챙겨 줬다고 믿는지도 몰라. 저 여자가 그걸 지레짐작으로 이해했을 뿐이고.","JPN":"ユイは兄さんが自分の面倒を見てくれたと本気で信じているのかもしれない。\\nあの女はそれをいち早く理解しただけ。","ENG":"Jia may believe that my brother really did care for her. As for that woman, she’s only speculating right now.","TWN":"小佳或許是真心以為，哥哥是好心派人來照顧她，而那女的只是有料到這一點而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어쨌거나 제일 귀찮은 기물이 사라진 건 사실이니까.","JPN":"とにかく、一番厄介な駒が消えたのは事実。","ENG":"No matter. At least the most annoying pieces are off the board.","TWN":"總之除掉最麻煩的棋子是事實！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"게다가 그런 장면을 본 이상……. 정신적으로 충분히 흔들릴 만하지.","JPN":"それにあんな場面を見た以上……\\n精神的に動揺しているはずよ。","ENG":"And after seeing what she saw... It’s only natural to be in shock.","TWN":"而且發生這種事……她的情緒也會受影響吧？"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L35_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아니, 신지아가 그렇게 인간미 넘치는 녀석이었나? 날 떠보려고 했을 가능성은?","JPN":"いや、ヒメノ・ユイってそんなに人間味あふれる性格だったっけ？\\n私を試そうとした可能性は？","ENG":"But was Shin Jia always this empathic? Or is she leading me on?","TWN":"不對，沈佳是這麼有人情味的人嗎？還是她是想探我的底？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"젠장!! 어처구니없는 수를 두니까 계획이 꼬여 버렸잖아!","JPN":"ああもうっ！！　無茶な手を選んだせいで計画がこじれてしまったじゃない！","ENG":"Damn it! Because of her move, my plan is getting all messed up!","TWN":"該死！！她下這步棋整個搞亂我的計畫！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……그래. 어쨌든 여기까지 왔어. 시기를 앞당기자.","JPN":"……いいわ。とにかくここまでは来れた。計画を早めよう。","ENG":"Okay... But I made it this far. I can get it moved up.","TWN":"……算了，事已至此，乾脆把時間提前吧！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아의 노림수가 뭔지 몰라도…….","JPN":"ユイの狙いが何かわからないけど……","ENG":"I don’t know what Jia’s up to, but...","TWN":"不知道她在打什麼主意……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"당하기 전에 이쪽에서 선수를 치는 거다!","JPN":"やられる前に、こちらから先手を打つ！","ENG":"I have to strike first before she does!","TWN":"我不如先下手為強！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};